//go:build ppc64le

package matchlen

import (
	"encoding/binary"
	"math/bits"

	"golang.org/x/sys/cpu"
)

// bulkMatchVSX compares a and b in 16-byte VSX blocks up to limit, returning the
// match length. Generated by go-asmgen (bulkmatch_ppc64le_gen.go), in
// bulkmatch_ppc64le.s. The kernel uses ISA-3.0 (POWER9) instructions (CNTTZD,
// Count Trailing Zeros Doubleword), which raise SIGILL on POWER8, so it runs
// only when hasVSX reports POWER9+.
func bulkMatchVSX(a, b []byte, limit int) int

// hasVSX is the dispatch flag. The generated kernel emits ISA-3.0 (POWER9)
// instructions (CNTTZD) that are illegal on POWER8, so it is gated on POWER9
// detection; on POWER8 bulkMatch falls back to the portable word-at-a-time
// scalar loop. It is a var (not a const) so the dispatch test can also drive the
// scalar fallback on a POWER9+ host.
var hasVSX = cpu.PPC64.IsPOWER9

// bulkMatch compares a and b in wide blocks up to limit, returning the match
// length. On POWER9+ it uses the VSX kernel; on POWER8 (where the kernel's
// CNTTZD would SIGILL) it uses the portable 8-byte word loop. Reading the words
// little-endian makes TrailingZeros find the lowest-index differing byte.
func bulkMatch(a, b []byte, limit int) int {
	if hasVSX {
		return bulkMatchVSX(a, b, limit)
	}
	i := 0
	for i+8 <= limit {
		if d := binary.LittleEndian.Uint64(a[i:]) ^ binary.LittleEndian.Uint64(b[i:]); d != 0 {
			return i + bits.TrailingZeros64(d)>>3
		}
		i += 8
	}
	return i
}
